package com.example.nofiltercoffee; import android.os.*; import android.widget.*; import androidx.appcompat.app.*;
public class PaymentMethodsActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.simple_page);findViewById(R.id.btnBack).setOnClickListener(v->finish());((TextView)findViewById(R.id.txtTitle)).setText("Payment Methods");String cards=UserSession.getCards(this);StringBuilder sb=new StringBuilder();if(cards.isEmpty())sb.append("No cards used yet.\n\nWhen you pay by card, the app saves that card automatically for this demo.");else{String[] rows=cards.split(";;");for(int i=0;i<rows.length;i++){String[] p=rows[i].split("\\|");if(p.length>=4)sb.append("CARD ").append(i+1).append("\nHolder: ").append(p[0]).append("\nNumber: ").append(p[1]).append("\nExpiry: ").append(p[2]).append("\nCVV: ").append(p[3]).append("\n\n");}}((TextView)findViewById(R.id.txtBody)).setText(sb.toString());}}
